/**
 * One-shot: drop the bad unique index on sharedLinks.linkId (allows multiple docs).
 * Usage (from repo root):  node api/scripts/fix-shared-link-index.js
 * Or from api/:              node scripts/fix-shared-link-index.js
 */
require("dotenv").config({ path: require("path").join(__dirname, "../../.env") });
const mongoose = require("mongoose");

const uri = process.env.MONGODB_URI || "mongodb://127.0.0.1:27017/docz";

async function main() {
  await mongoose.connect(uri);
  const dbName = mongoose.connection.name;
  const coll = mongoose.connection.collection("documents");
  const indexes = await coll.indexes();
  console.log(`Connected to db "${dbName}". Indexes on documents:`);
  for (const idx of indexes) {
    console.log("-", idx.name, JSON.stringify(idx.key), idx.unique ? "(unique)" : "");
    const key = idx.key || {};
    if (
      Object.keys(key).length === 1 &&
      key["sharedLinks.linkId"] === 1 &&
      idx.unique
    ) {
      await coll.dropIndex(idx.name);
      console.log(`Dropped: ${idx.name}`);
    }
  }
  await mongoose.disconnect();
  console.log("Done.");
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
